INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_01$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The corridor is orderly. Signs indicate direction. The signs have been recently updated.$Q$, $Q$Der Korridor ist ordentlich. Schilder weisen die Richtung. Die Schilder wurden kürzlich aktualisiert.$Q$, NULL, NULL, 0) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_02$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Alliance offered. Alliance accepted. The cost will be announced later.$Q$, $Q$Bündnis angeboten. Bündnis angenommen. Die Kosten werden später bekanntgegeben.$Q$, NULL, NULL, 1) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_03$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Everyone sees what you appear to be. Few experience what you really are. The Spiegelpalast sees both.$Q$, $Q$Jeder sieht, was ihr zu sein scheint. Wenige erfahren, was ihr wirklich seid. Der Spiegelpalast sieht beides.$Q$, NULL, NULL, 2) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_04$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$A faction representative nods at {agent}. The nod is precisely calibrated: acknowledgment without commitment.$Q$, $Q$Ein Fraktionsvertreter nickt {agent} zu. Das Nicken ist präzise kalibriert: Anerkennung ohne Verpflichtung.$Q$, NULL, NULL, 3) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_05$Q$, $Q$The Overthrow$Q$, $Q$combat_won$Q$, $JB${}$JB$::jsonb, $Q$The enforcers are down. The report will say they were never here. The revised report will say {agent} was never here either.$Q$, $Q$Die Vollstrecker sind am Boden. Der Bericht wird sagen, sie waren nie hier. Der überarbeitete Bericht wird sagen, {agent} war auch nie hier.$Q$, NULL, NULL, 4) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_06$Q$, $Q$The Overthrow$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The faction leader smiles. The smile has been authorized.$Q$, $Q$Der Fraktionsführer lächelt. Das Lächeln wurde genehmigt.$Q$, NULL, NULL, 5) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_07$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Three factions. Three truths. None of them are lying. This is the problem.$Q$, $Q$Drei Fraktionen. Drei Wahrheiten. Keine davon lügt. Das ist das Problem.$Q$, NULL, NULL, 6) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_08$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q${agent} is offered a seat at the table. The seat is comfortable. The table is set for fewer people than it was yesterday.$Q$, $Q${agent} wird ein Platz am Tisch angeboten. Der Sitz ist bequem. Der Tisch ist für weniger Personen gedeckt als gestern.$Q$, NULL, NULL, 7) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_09$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Walls have ears. These walls have faction insignia. The insignia changed since the party entered.$Q$, $Q$Wände haben Ohren. Diese Wände haben Fraktionsabzeichen. Die Abzeichen haben sich geändert, seit die Gruppe eintrat.$Q$, NULL, NULL, 8) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_10$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$»Erst kommt das Bündnis«, sagt der Fraktionsführer. »Dann kommt die Wahrheit. Falls noch jemand fragt.«$Q$, $Q$»Erst kommt das Bündnis«, sagt der Fraktionsführer. »Dann kommt die Wahrheit. Falls noch jemand fragt.«$Q$, NULL, NULL, 9) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_11$Q$, $Q$The Overthrow$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The enforcers make speeches while fighting. They die with quotable last words. The Overthrow is theatrical even in violence.$Q$, $Q$Die Vollstrecker halten Reden, während sie kämpfen. Sie sterben mit zitierwürdigen letzten Worten. Der Umsturz ist selbst in der Gewalt theatralisch.$Q$, NULL, NULL, 10) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_12$Q$, $Q$The Overthrow$Q$, $Q$combat_won$Q$, $JB${}$JB$::jsonb, $Q$The enforcers are down. Which faction sent them? The answer depends on which faction asks.$Q$, $Q$Die Vollstrecker sind am Boden. Welche Fraktion hat sie geschickt? Die Antwort hängt davon ab, welche Fraktion fragt.$Q$, NULL, NULL, 11) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_13$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${"conscientiousness_high": true}$JB$::jsonb, $Q${agent} reads the new decree. It contradicts the previous decree. Both remain in effect. Doublethink.$Q$, $Q${agent} liest das neue Dekret. Es widerspricht dem vorherigen Dekret. Beide bleiben in Kraft. Doppeldenk.$Q$, NULL, NULL, 12) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_14$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The old leader is gone. The new leader enters. Same room. Same desk. Same view from the window.$Q$, $Q$Der alte Anführer ist weg. Der neue Anführer tritt ein. Derselbe Raum. Derselbe Schreibtisch. Dieselbe Aussicht.$Q$, NULL, NULL, 13) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_15$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Every revolutionary ends as an oppressor or a heretic. The Spiegelpalast offers both options. Choose quickly.$Q$, $Q$Jeder Revolutionär endet als Unterdrücker oder als Ketzer. Der Spiegelpalast bietet beide Optionen. Wählt schnell.$Q$, NULL, NULL, 14) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_16$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q${agent} joins the revolution. The revolution has a sign-up sheet. The sign-up sheet has a second page that is not immediately visible.$Q$, $Q${agent} schließt sich der Revolution an. Die Revolution hat eine Anmeldeliste. Die Anmeldeliste hat eine zweite Seite, die nicht sofort sichtbar ist.$Q$, NULL, NULL, 15) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_17$Q$, $Q$The Overthrow$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The party can never be mistaken. {agent} can make a mistake. Not the party. Not the faction. Fight accordingly.$Q$, $Q$Die Partei kann sich nie irren. {agent} kann sich irren. Nicht die Partei. Nicht die Fraktion. Kämpft entsprechend.$Q$, NULL, NULL, 16) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_18$Q$, $Q$The Overthrow$Q$, $Q$combat_won$Q$, $JB${}$JB$::jsonb, $Q$Victory. The revolution devours its children — but not today. Today, the children devour.$Q$, $Q$Sieg. Die Revolution frisst ihre Kinder — aber nicht heute. Heute fressen die Kinder.$Q$, NULL, NULL, 17) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_19$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${"agreeableness_high": true}$JB$::jsonb, $Q${agent} tries to mediate between factions. Both sides thank {agent}. Both sides add {agent}'s name to a list that is not labeled 'mediators.'$Q$, $Q${agent} versucht, zwischen den Fraktionen zu vermitteln. Beide Seiten danken {agent}. Beide Seiten setzen {agent}s Namen auf eine Liste, die nicht 'Vermittler' heißt.$Q$, NULL, NULL, 18) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_20$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Macht. Macht des Machens. Spiegel. Spiegel des Spiegels. Wer regiert?$Q$, $Q$Macht. Macht des Machens. Spiegel. Spiegel des Spiegels. Wer regiert?$Q$, NULL, NULL, 19) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_21$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$The Pretender speaks. {agent} has heard these words before — in their own voice, on Floor 1.$Q$, $Q$Der Prätendent spricht. {agent} hat diese Worte schon gehört — in der eigenen Stimme, auf Etage 1.$Q$, NULL, NULL, 20) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_22$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$All factions are equal. But some factions are more equal than others. The sign was always there. The party is only now able to read it.$Q$, $Q$Alle Fraktionen sind gleich. Aber manche Fraktionen sind gleicher als andere. Das Schild war immer da. Die Gruppe kann es erst jetzt lesen.$Q$, NULL, NULL, 21) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_23$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$»Wir haben Ihre Akte gelesen. Eine bemerkenswerte Karriere. Leider müssen wir sie umschreiben.«$Q$, $Q$»Wir haben Ihre Akte gelesen. Eine bemerkenswerte Karriere. Leider müssen wir sie umschreiben.«$Q$, NULL, NULL, 22) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_24$Q$, $Q$The Overthrow$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$The boot. The face. Forever. But whose boot? The answer changes with the faction.$Q$, $Q$Der Stiefel. Das Gesicht. Für immer. Aber wessen Stiefel? Die Antwort wechselt mit der Fraktion.$Q$, NULL, NULL, 23) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_25$Q$, $Q$The Overthrow$Q$, $Q$combat_won$Q$, $JB${}$JB$::jsonb, $Q$»Ihr wolltet Freiheit. Ich wollte Freiheit. Seht, was wir daraus gemacht haben.«$Q$, $Q$»Ihr wolltet Freiheit. Ich wollte Freiheit. Seht, was wir daraus gemacht haben.«$Q$, NULL, NULL, 24) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_26$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${}$JB$::jsonb, $Q$Loyalty costs nothing. Disloyalty costs everything. Both are true. Welcome to the Overthrow.$Q$, $Q$Treue kostet nichts. Untreue kostet alles. Beides ist wahr. Willkommen im Umsturz.$Q$, NULL, NULL, 25) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_27$Q$, $Q$The Overthrow$Q$, $Q$room_entered$Q$, $JB${"openness_high": true}$JB$::jsonb, $Q$»Der Spiegelpalast zeigt jedem, was er sehen will. Nicht was er ist. Was er will. Das ist schlimmer.«$Q$, $Q$»Der Spiegelpalast zeigt jedem, was er sehen will. Nicht was er ist. Was er will. Das ist schlimmer.«$Q$, NULL, NULL, 26) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_banter (id, archetype, trigger, personality_filter, text_en, text_de, decay_tier, attachment_tier, sort_order) VALUES ($Q$ob_28$Q$, $Q$The Overthrow$Q$, $Q$combat_start$Q$, $JB${}$JB$::jsonb, $Q$Power is not a means; it is an end. One does not establish a dictatorship to safeguard a revolution. The Pretender knows this. {agent} is learning.$Q$, $Q$Macht ist kein Mittel; sie ist ein Zweck. Man errichtet keine Diktatur, um eine Revolution zu sichern. Der Prätendent weiß das. {agent} lernt.$Q$, NULL, NULL, 27) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, trigger = EXCLUDED.trigger, personality_filter = EXCLUDED.personality_filter, text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de, decay_tier = EXCLUDED.decay_tier, attachment_tier = EXCLUDED.attachment_tier, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_enemy_templates (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$overthrow_faction_informer$Q$, $Q$Faction Informer$Q$, $Q$Fraktionsspitzel$Q$, $Q$The Overthrow$Q$, 1, 25, $Q$minion$Q$, $Q$spy$Q$, 2, 4, true, 45, ARRAY[$Q$infiltrator$Q$]::text[], ARRAY[$Q$spy$Q$]::text[], $JB${"stress_attack": 45, "evade": 30, "denounce": 15, "ambient": 10}$JB$::jsonb, ARRAY[$Q$denounce$Q$]::text[], $Q$Havel's greengrocer made operative. The informer does not believe — the informer performs. The sign in the window says what the faction requires. Behind the counter, the informer reports who does not display theirs.$Q$, $Q$Havels Gemüsehändler, zum Agenten geworden. Der Spitzel glaubt nicht — der Spitzel führt auf. Das Schild im Fenster sagt, was die Fraktion verlangt. Hinter der Theke meldet der Spitzel, wer seines nicht zeigt.$Q$, ARRAY[$Q$The informer smiles at {agent}. The smile has been authorized.$Q$, $Q$A clipboard. Names. {agent}'s is already on the list.$Q$]::text[], ARRAY[$Q$Der Spitzel lächelt {agent} an. Das Lächeln wurde genehmigt.$Q$, $Q$Eine Zwischenablage. Namen. {agent}s steht bereits auf der Liste.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$overthrow_propaganda_agent$Q$, $Q$Propaganda Agent$Q$, $Q$Propagandaagent$Q$, $Q$The Overthrow$Q$, 2, 70, $Q$standard$Q$, $Q$propagandist$Q$, 3, 6, true, 20, ARRAY[$Q$guardian$Q$]::text[], ARRAY[$Q$propagandist$Q$, $Q$spy$Q$]::text[], $JB${"stress_attack": 40, "rewrite": 25, "attack": 20, "ambient": 15}$JB$::jsonb, ARRAY[$Q$rewrite$Q$]::text[], $Q$Orwell's Squealer on two legs. The agent does not lie — the agent renders the concept of lying meaningless. Yesterday's alliance was always today's betrayal. The records have been updated. The records were always thus.$Q$, $Q$Orwells Schwatzwutz auf zwei Beinen. Der Agent lügt nicht — der Agent macht den Begriff des Lügens bedeutungslos. Das gestrige Bündnis war schon immer der heutige Verrat. Die Akten wurden aktualisiert. Die Akten waren immer so.$Q$, ARRAY[$Q$The agent reads aloud. {agent} has heard these words before — in their own voice.$Q$, $Q$History is being revised. The revision is already the third this floor.$Q$]::text[], ARRAY[$Q$Der Agent liest vor. {agent} hat diese Worte schon gehört — in der eigenen Stimme.$Q$, $Q$Die Geschichte wird überarbeitet. Die Überarbeitung ist bereits die dritte auf dieser Etage.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$overthrow_regime_enforcer$Q$, $Q$Regime Enforcer$Q$, $Q$Regimevollstrecker$Q$, $Q$The Overthrow$Q$, 2, 60, $Q$standard$Q$, $Q$guardian$Q$, 5, 3, true, 10, ARRAY[$Q$assassin$Q$]::text[], ARRAY[$Q$saboteur$Q$, $Q$infiltrator$Q$]::text[], $JB${"attack": 45, "stress_attack": 20, "defend": 20, "ambient": 15}$JB$::jsonb, ARRAY[$Q$suppress$Q$]::text[], $Q$The muscle behind the rhetoric. The enforcer does not care which faction gives the order — only that the order exists. Arendt's ideal subject: one for whom the distinction between fact and fiction has ceased to matter.$Q$, $Q$Die Muskeln hinter der Rhetorik. Der Vollstrecker kümmert sich nicht, welche Fraktion den Befehl gibt — nur dass der Befehl existiert. Arendts ideales Subjekt: eines, für das der Unterschied zwischen Tatsache und Fiktion aufgehört hat zu zählen.$Q$, ARRAY[$Q$The enforcer does not think. The enforcer processes. This is the advantage.$Q$, $Q${agent} sees the enforcer's eyes. There is no ideology in them. Only compliance.$Q$]::text[], ARRAY[$Q$Der Vollstrecker denkt nicht. Der Vollstrecker verarbeitet. Das ist der Vorteil.$Q$, $Q${agent} sieht die Augen des Vollstreckers. Keine Ideologie darin. Nur Gehorsam.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$overthrow_grand_inquisitor$Q$, $Q$Grand Inquisitor$Q$, $Q$Großinquisitor$Q$, $Q$The Overthrow$Q$, 4, 100, $Q$elite$Q$, $Q$propagandist$Q$, 4, 8, true, 15, ARRAY[$Q$spy$Q$, $Q$propagandist$Q$]::text[], ARRAY[$Q$guardian$Q$]::text[], $JB${"stress_attack": 35, "interrogate": 25, "attack": 20, "defend": 10, "ambient": 10}$JB$::jsonb, ARRAY[$Q$interrogate$Q$]::text[], $Q$Dostoevsky's three powers made flesh: miracle, mystery, authority. The Inquisitor does not punish dissent — the Inquisitor explains why dissent was always agreement, misunderstood. The confession is not extracted. It is assisted.$Q$, $Q$Dostojewskis drei Mächte, Fleisch geworden: Wunder, Geheimnis, Autorität. Der Inquisitor bestraft keinen Dissens — der Inquisitor erklärt, warum Dissens immer Zustimmung war, nur missverstanden. Das Geständnis wird nicht erzwungen. Es wird begleitet.$Q$, ARRAY[$Q$The Inquisitor smiles. The smile contains three thousand years of practice.$Q$, $Q$'We corrected Thy work,' the Inquisitor says. 'And men rejoiced.'$Q$]::text[], ARRAY[$Q$Der Inquisitor lächelt. Das Lächeln enthält dreitausend Jahre Übung.$Q$, $Q$»Wir haben Dein Werk korrigiert«, sagt der Inquisitor. »Und die Menschen freuten sich.«$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_enemy_templates (id, name_en, name_de, archetype, condition_threshold, stress_resistance, threat_level, attack_aptitude, attack_power, stress_attack_power, telegraphed_intent, evasion, resistances, vulnerabilities, action_weights, special_abilities, description_en, description_de, ambient_text_en, ambient_text_de) VALUES ($Q$overthrow_the_pretender$Q$, $Q$The Pretender$Q$, $Q$Der Prätendent$Q$, $Q$The Overthrow$Q$, 6, 120, $Q$boss$Q$, $Q$propagandist$Q$, 5, 9, false, 20, ARRAY[$Q$assassin$Q$, $Q$saboteur$Q$]::text[], ARRAY[$Q$spy$Q$, $Q$propagandist$Q$]::text[], $JB${"stress_attack": 30, "rhetoric": 25, "attack": 20, "rewrite": 15, "ambient": 10}$JB$::jsonb, ARRAY[$Q$rhetoric$Q$, $Q$rewrite$Q$]::text[], $Q$Milton's Satan made sovereign. The Pretender began as a rebel — magnificent, defiant, charismatic. Power degraded the vision. Phase 1: Book I archangel, addressing armies with impossible eloquence. Phase 2: Book IV, 'squat like a toad,' truth exposed. Phase 3: Book X, permanently serpentine. The Pretender quotes everyone. Especially you.$Q$, $Q$Miltons Satan, zum Souverän geworden. Der Prätendent begann als Rebell — prächtig, trotzig, charismatisch. Die Macht zersetzte die Vision. Phase 1: Erzengel aus Buch I, Armeen ansprechend mit unmöglicher Eloquenz. Phase 2: Buch IV, 'hockend wie eine Kröte,' Wahrheit enthüllt. Phase 3: Buch X, dauerhaft zur Schlange geworden. Der Prätendent zitiert alle. Besonders euch.$Q$, ARRAY[$Q$The Pretender speaks. {agent} has heard these words before — in their own voice, on Floor 1.$Q$, $Q$'You said you were here for freedom. I said that too, once.'$Q$, $Q$The mirror shows {agent} and the Pretender. The reflection is the same.$Q$]::text[], ARRAY[$Q$Der Prätendent spricht. {agent} hat diese Worte schon gehört — in der eigenen Stimme, auf Etage 1.$Q$, $Q$»Ihr sagtet, ihr seid für die Freiheit hier. Das sagte ich auch, einmal.«$Q$, $Q$Der Spiegel zeigt {agent} und den Prätendenten. Die Spiegelung ist dieselbe.$Q$]::text[]) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, archetype = EXCLUDED.archetype, condition_threshold = EXCLUDED.condition_threshold, stress_resistance = EXCLUDED.stress_resistance, threat_level = EXCLUDED.threat_level, attack_aptitude = EXCLUDED.attack_aptitude, attack_power = EXCLUDED.attack_power, stress_attack_power = EXCLUDED.stress_attack_power, telegraphed_intent = EXCLUDED.telegraphed_intent, evasion = EXCLUDED.evasion, resistances = EXCLUDED.resistances, vulnerabilities = EXCLUDED.vulnerabilities, action_weights = EXCLUDED.action_weights, special_abilities = EXCLUDED.special_abilities, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, ambient_text_en = EXCLUDED.ambient_text_en, ambient_text_de = EXCLUDED.ambient_text_de;
INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($Q$overthrow_informer_patrol_spawn$Q$, $Q$The Overthrow$Q$, $JB$[{"template_id": "overthrow_faction_informer", "count": 2}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
