INSERT INTO dungeon_spawn_configs (id, archetype, entries) VALUES ($Q$overthrow_pretender_spawn$Q$, $Q$The Overthrow$Q$, $JB$[{"template_id": "overthrow_the_pretender", "count": 1}, {"template_id": "overthrow_propaganda_agent", "count": 1}]$JB$::jsonb) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, entries = EXCLUDED.entries;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_informer_patrol$Q$, $Q$The Overthrow$Q$, $Q$combat$Q$, 1, 3, 1, $Q$Two figures in the corridor, checking papers. They are not soldiers — they are informers. The clipboard is more dangerous than a weapon.$Q$, $Q$Zwei Gestalten im Korridor, Papiere prüfend. Sie sind keine Soldaten — sie sind Spitzel. Die Zwischenablage ist gefährlicher als eine Waffe.$Q$, $Q$overthrow_informer_patrol_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_propaganda_escort$Q$, $Q$The Overthrow$Q$, $Q$combat$Q$, 2, 4, 1, $Q$A propaganda agent, escorted by an informer. The agent carries revised documents. The revisions rewrite something the party remembers differently.$Q$, $Q$Ein Propagandaagent, eskortiert von einem Spitzel. Der Agent trägt überarbeitete Dokumente. Die Überarbeitungen schreiben etwas um, das die Gruppe anders in Erinnerung hat.$Q$, $Q$overthrow_propaganda_patrol_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_enforcer_checkpoint$Q$, $Q$The Overthrow$Q$, $Q$combat$Q$, 2, 5, 1, $Q$A checkpoint. The enforcer does not ask for papers — the enforcer asks for allegiance. The question is not 'who are you' but 'who are you for.'$Q$, $Q$Ein Kontrollpunkt. Der Vollstrecker fragt nicht nach Papieren — der Vollstrecker fragt nach Treue. Die Frage ist nicht 'Wer seid ihr' sondern 'Für wen seid ihr.'$Q$, $Q$overthrow_enforcer_squad_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_political_clash$Q$, $Q$The Overthrow$Q$, $Q$combat$Q$, 3, 6, 1, $Q$Two faction operatives — a propagandist and an enforcer — from different factions, mid-argument. The argument has become kinetic. The party walks into the crossfire.$Q$, $Q$Zwei Fraktionsagenten — ein Propagandist und ein Vollstrecker — aus verschiedenen Fraktionen, mitten im Streit. Der Streit ist kinetisch geworden. Die Gruppe gerät ins Kreuzfeuer.$Q$, $Q$overthrow_political_crisis_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_inquisition_encounter$Q$, $Q$The Overthrow$Q$, $Q$combat$Q$, 4, 7, 2, $Q$The Grand Inquisitor waits. An informer takes notes. This is not an ambush — it is a tribunal. The party has already been found guilty. The sentence is an invitation to confess.$Q$, $Q$Der Großinquisitor wartet. Ein Spitzel macht Notizen. Dies ist kein Hinterhalt — es ist ein Tribunal. Die Gruppe wurde bereits schuldig gesprochen. Das Urteil ist eine Einladung zum Geständnis.$Q$, $Q$overthrow_inquisition_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_purge_squad$Q$, $Q$The Overthrow$Q$, $Q$combat$Q$, 3, 7, 2, $Q$The revolution devours its children. Vergniaud's prophecy made operational: a squad sent to purge yesterday's allies. The enforcer leads. The informer has already filed the report.$Q$, $Q$Die Revolution frisst ihre Kinder. Vergniauds Prophezeiung, operational gemacht: ein Trupp, gesandt um gestrige Verbündete zu säubern. Der Vollstrecker führt. Der Spitzel hat den Bericht bereits eingereicht.$Q$, $Q$overthrow_political_crisis_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_faction_offer$Q$, $Q$The Overthrow$Q$, $Q$encounter$Q$, 1, 3, 1, $Q$A faction representative approaches. The offer is simple: alliance in exchange for a service. The service is not specified in advance. Alliance offered. Alliance accepted. The cost will be announced later.$Q$, $Q$Ein Fraktionsvertreter nähert sich. Das Angebot ist einfach: Bündnis im Austausch für einen Dienst. Der Dienst wird nicht im Voraus spezifiziert. Bündnis angeboten. Bündnis angenommen. Die Kosten werden später bekanntgegeben.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_show_trial$Q$, $Q$The Overthrow$Q$, $Q$encounter$Q$, 2, 5, 1, $Q$A trial is in progress. The accused is a former faction leader. The evidence is their own biography — rewritten. Kiš''s archival voice: clinical, footnoted, devastating. The verdict was decided before the trial began.$Q$, $Q$Ein Prozess ist im Gange. Der Angeklagte ist ein ehemaliger Fraktionsführer. Der Beweis ist die eigene Biographie — umgeschrieben. Kišs Archivstimme: klinisch, fußnotiert, verheerend. Das Urteil stand vor Prozessbeginn fest.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_greengrocers_window$Q$, $Q$The Overthrow$Q$, $Q$encounter$Q$, 1, 4, 1, $Q$A room with signs. Each sign bears a slogan. The slogans are contradictory. To pass through, the party must display one. Havel''s greengrocer: the sign means nothing. The act of displaying it means everything.$Q$, $Q$Ein Raum mit Schildern. Jedes Schild trägt eine Parole. Die Parolen widersprechen sich. Um durchzukommen, muss die Gruppe eines zeigen. Havels Gemüsehändler: das Schild bedeutet nichts. Der Akt des Zeigens bedeutet alles.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_erased_portrait$Q$, $Q$The Overthrow$Q$, $Q$encounter$Q$, 2, 6, 1, $Q$A gallery of portraits. Several have been scratched out. The scratched-out faces were faction leaders, two floors ago. Kundera''s Clementis photograph: the body erased, the hat remaining on Gottwald''s head.$Q$, $Q$Eine Galerie von Porträts. Mehrere wurden ausgekratzt. Die ausgekratzten Gesichter waren Fraktionsführer, zwei Etagen zuvor. Kunderas Clementis-Foto: der Körper gelöscht, die Pelzmütze noch auf Gottwalds Kopf.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_variety_theater$Q$, $Q$The Overthrow$Q$, $Q$encounter$Q$, 3, 7, 1, $Q$Bulgakov''s Variety Theater. Money rains from the ceiling. The factions scramble. In three rooms, the money will turn to blank paper. But right now, it is real. The question: what do the factions do when given exactly what they want?$Q$, $Q$Bulgakows Varietétheater. Geld regnet von der Decke. Die Fraktionen stürzen sich darauf. In drei Räumen wird das Geld zu leerem Papier. Aber gerade jetzt ist es echt. Die Frage: was tun die Fraktionen, wenn sie genau das bekommen, was sie wollen?$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_grand_inquisitor$Q$, $Q$The Overthrow$Q$, $Q$elite$Q$, 3, 7, 1, $Q$The Grand Inquisitor''s chamber. Three seats: miracle, mystery, authority. Dostoevsky''s three powers, made architectural. The Inquisitor does not ask questions. The Inquisitor provides the answers and waits for the party to agree.$Q$, $Q$Die Kammer des Großinquisitors. Drei Sitze: Wunder, Geheimnis, Autorität. Dostojewskis drei Mächte, architektonisch umgesetzt. Der Inquisitor stellt keine Fragen. Der Inquisitor liefert die Antworten und wartet, dass die Gruppe zustimmt.$Q$, $Q$overthrow_inquisition_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_the_pretender_boss$Q$, $Q$The Overthrow$Q$, $Q$boss$Q$, 4, 99, 1, $Q$Der Spiegelpalast reveals its center: a throne room where every mirror reflects a different version of the same face. The Pretender sits. Milton''s Satan at the zenith: magnificent, eloquent, utterly convinced. ''Better to reign in Hell, than serve in Heaven.'' The deterioration has not yet begun. It begins now.$Q$, $Q$Der Spiegelpalast enthüllt sein Zentrum: ein Thronsaal, in dem jeder Spiegel eine andere Version desselben Gesichts reflektiert. Der Prätendent sitzt. Miltons Satan am Zenit: prächtig, eloquent, vollkommen überzeugt. ''Besser in der Hölle herrschen als im Himmel dienen.'' Die Zersetzung hat noch nicht begonnen. Sie beginnt jetzt.$Q$, $Q$overthrow_pretender_spawn$Q$) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_safe_house$Q$, $Q$The Overthrow$Q$, $Q$rest$Q$, 1, 4, 1, $Q$A safe house. The walls are thin. The conversations on the other side are about the party. But for now, the door is closed.$Q$, $Q$Ein sicheres Haus. Die Wände sind dünn. Die Gespräche auf der anderen Seite handeln von der Gruppe. Aber vorerst ist die Tür geschlossen.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_neutral_ground$Q$, $Q$The Overthrow$Q$, $Q$rest$Q$, 3, 7, 1, $Q$Neutral ground. All factions have agreed — temporarily — that this room is outside the game. The agreement holds because all sides are exhausted. Camus: one must imagine Sisyphus happy. The boulder rests here.$Q$, $Q$Neutrales Gelände. Alle Fraktionen haben sich — vorübergehend — darauf geeinigt, dass dieser Raum außerhalb des Spiels liegt. Die Vereinbarung hält, weil alle Seiten erschöpft sind. Camus: man muss sich Sisyphos als glücklichen Menschen vorstellen. Der Felsbrocken ruht hier.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_faction_archive$Q$, $Q$The Overthrow$Q$, $Q$treasure$Q$, 1, 5, 1, $Q$An archive. Dossiers on every faction, every leader, every operative. Kadare''s Palace of Dreams — except these are waking reports, not sleeping ones.$Q$, $Q$Ein Archiv. Dossiers über jede Fraktion, jeden Anführer, jeden Agenten. Kadares Palast der Träume — nur dass dies Wachberichte sind, keine Schlafberichte.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_templates (id, archetype, room_type, min_depth, max_depth, min_difficulty, description_en, description_de, combat_encounter_id) VALUES ($Q$ov_confiscated_assets$Q$, $Q$The Overthrow$Q$, $Q$treasure$Q$, 3, 7, 1, $Q$A room of confiscated assets. Former leaders'' possessions, labeled and catalogued. Each label is a name. Each name is scratched out.$Q$, $Q$Ein Raum mit beschlagnahmten Gütern. Besitztümer ehemaliger Anführer, beschriftet und katalogisiert. Jedes Etikett ist ein Name. Jeder Name ist durchgestrichen.$Q$, NULL) ON CONFLICT (id) DO UPDATE SET archetype = EXCLUDED.archetype, room_type = EXCLUDED.room_type, min_depth = EXCLUDED.min_depth, max_depth = EXCLUDED.max_depth, min_difficulty = EXCLUDED.min_difficulty, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, combat_encounter_id = EXCLUDED.combat_encounter_id;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$faction_accept$Q$, $Q$ov_faction_offer$Q$, $Q$Accept the alliance (Propagandist)$Q$, $Q$Das Bündnis annehmen (Propagandist)$Q$, $Q$propagandist$Q$, -5, $JB${"fracture": 3, "faction_standing": {"current_floor_faction": 15}}$JB$::jsonb, $JB${"fracture": 5, "faction_standing": {"current_floor_faction": 8}}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $Q${agent} negotiates terms. The terms are favorable — or appear to be. The representative nods. The alliance is entered into the record. Records can be revised.$Q$, $Q${agent} verhandelt die Bedingungen. Die Bedingungen sind günstig — oder scheinen es zu sein. Der Vertreter nickt. Das Bündnis wird aktenkundig. Akten können überarbeitet werden.$Q$, $Q${agent} negotiates. The terms are accepted — but the representative adds a clause at the end, spoken too quickly to parse. Machiavelli''s fox: the contract is signed. The footnote is not.$Q$, $Q${agent} verhandelt. Die Bedingungen werden akzeptiert — aber der Vertreter fügt am Ende eine Klausel hinzu, zu schnell gesprochen um sie zu erfassen. Machiavellis Fuchs: der Vertrag ist unterschrieben. Die Fußnote nicht.$Q$, $Q$The negotiation collapses. The representative''s smile does not change. The smile was never contingent on the outcome.$Q$, $Q$Die Verhandlung scheitert. Das Lächeln des Vertreters ändert sich nicht. Das Lächeln war nie vom Ergebnis abhängig.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$faction_spy$Q$, $Q$ov_faction_offer$Q$, $Q$Gather intelligence on the faction first (Spy)$Q$, $Q$Erst Informationen über die Fraktion sammeln (Spion)$Q$, $Q$spy$Q$, 0, $JB${"fracture": 2}$JB$::jsonb, $JB${"fracture": 3}$JB$::jsonb, $JB${"fracture": 5, "stress": 5}$JB$::jsonb, $Q${agent} reads the offer beneath the offer. Every faction has a second agenda. The Spy sees both.$Q$, $Q${agent} liest das Angebot unter dem Angebot. Jede Fraktion hat eine zweite Agenda. Der Spion sieht beide.$Q$, $Q${agent} sees the second agenda. But a third remains hidden — Kadare''s Palace has sub-basements. Partial intelligence is the most dangerous kind.$Q$, $Q${agent} sieht die zweite Agenda. Aber eine dritte bleibt verborgen — Kadares Palast hat Untergeschosse. Teilwissen ist die gefährlichste Art.$Q$, $Q$The intelligence is incomplete. What {agent} does not know is being reported to someone else.$Q$, $Q$Die Aufklärung ist unvollständig. Was {agent} nicht weiß, wird jemand anderem gemeldet.$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$faction_decline$Q$, $Q$ov_faction_offer$Q$, $Q$Decline. Remain unaligned.$Q$, $Q$Ablehnen. Ungebunden bleiben.$Q$, NULL, 0, $JB${"fracture": 5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The representative leaves. The absence of alliance is itself a political statement. Neutrality is the most expensive position in the Spiegelpalast.$Q$, $Q$Der Vertreter geht. Die Abwesenheit eines Bündnisses ist selbst eine politische Aussage. Neutralität ist die teuerste Position im Spiegelpalast.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$trial_defend$Q$, $Q$ov_show_trial$Q$, $Q$Speak in the accused''s defense (Propagandist)$Q$, $Q$Zur Verteidigung des Angeklagten sprechen (Propagandist)$Q$, $Q$propagandist$Q$, 5, $JB${"fracture": -5, "stress_heal": 10}$JB$::jsonb, $JB${"fracture": 3}$JB$::jsonb, $JB${"fracture": 10, "stress": 15}$JB$::jsonb, $Q${agent} speaks. Antony''s rhetoric: never say the accusers are liars. Let the crowd arrive there themselves. The tribunal hesitates. The accused is not freed — but the sentence is deferred.$Q$, $Q${agent} spricht. Antonius'' Rhetorik: sag nie, dass die Ankläger lügen. Lass die Menge selbst dorthin kommen. Das Tribunal zögert. Der Angeklagte wird nicht befreit — aber das Urteil wird aufgeschoben.$Q$, $Q${agent} speaks. The tribunal listens — but the way Koestler''s Gletkin listens: recording, not hearing. The defense enters the record. The record is another kind of evidence.$Q$, $Q${agent} spricht. Das Tribunal hört zu — aber so wie Koestlers Gletkin zuhört: aufzeichnend, nicht hörend. Die Verteidigung geht in die Akten ein. Die Akten sind eine andere Art von Beweis.$Q$, $Q$The defense fails. {agent}''s words are entered into evidence — as proof of complicity.$Q$, $Q$Die Verteidigung scheitert. {agent}s Worte werden als Beweis aufgenommen — als Beweis der Mittäterschaft.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$trial_observe$Q$, $Q$ov_show_trial$Q$, $Q$Observe the trial''s mechanism (Spy)$Q$, $Q$Den Mechanismus des Prozesses beobachten (Spion)$Q$, $Q$spy$Q$, -5, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 5}$JB$::jsonb, $Q${agent} watches. The trial is not about guilt — it is about demonstration. Brecht''s Verfremdung: once you see the mechanism, you cannot un-see it.$Q$, $Q${agent} beobachtet. Der Prozess handelt nicht von Schuld — er handelt von Demonstration. Brechts Verfremdung: hat man den Mechanismus einmal gesehen, kann man es nicht rückgängig machen.$Q$, $Q${agent} sees the mechanism — partially. Kiš''s archive: some footnotes are legible, others redacted. The trial is a text. {agent} has read enough to know the ending is already written.$Q$, $Q${agent} sieht den Mechanismus — teilweise. Kišs Archiv: manche Fußnoten sind lesbar, andere geschwärzt. Der Prozess ist ein Text. {agent} hat genug gelesen um zu wissen, dass das Ende bereits geschrieben ist.$Q$, $Q$The mechanism is visible. But visibility is not protection.$Q$, $Q$Der Mechanismus ist sichtbar. Aber Sichtbarkeit ist kein Schutz.$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$trial_pass$Q$, $Q$ov_show_trial$Q$, $Q$Leave before the verdict.$Q$, $Q$Vor dem Urteil gehen.$Q$, NULL, 0, $JB${"fracture": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party leaves. The trial continues without them. Silence is complicity. But so is everything else.$Q$, $Q$Die Gruppe geht. Der Prozess geht ohne sie weiter. Schweigen ist Mittäterschaft. Aber alles andere auch.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$greengrocer_perform$Q$, $Q$ov_greengrocers_window$Q$, $Q$Display the dominant faction''s sign (Infiltrator)$Q$, $Q$Das Schild der dominanten Fraktion zeigen (Infiltrator)$Q$, $Q$infiltrator$Q$, -5, $JB${"fracture": 3}$JB$::jsonb, $JB${"fracture": 4}$JB$::jsonb, $JB${"fracture": 6, "stress": 5}$JB$::jsonb, $Q$The sign is displayed. No one checks if the party believes it. Belief was never the point. Performance is the currency of the Spiegelpalast.$Q$, $Q$Das Schild wird gezeigt. Niemand prüft, ob die Gruppe daran glaubt. Glaube war nie der Punkt. Aufführung ist die Währung des Spiegelpalasts.$Q$, $Q$The sign is displayed. Someone pauses — reads it a moment too long. Havel''s greengrocer, observed: the performance passes, but it has been noted. Not the sign. The hesitation before it.$Q$, $Q$Das Schild wird gezeigt. Jemand hält inne — liest es einen Moment zu lang. Havels Gemüsehändler, beobachtet: die Aufführung geht durch, aber sie wurde notiert. Nicht das Schild. Das Zögern davor.$Q$, $Q$The performance is unconvincing. Not the words — the posture. The body knows what the mouth denies.$Q$, $Q$Die Aufführung ist nicht überzeugend. Nicht die Worte — die Haltung. Der Körper weiß, was der Mund leugnet.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$greengrocer_refuse$Q$, $Q$ov_greengrocers_window$Q$, $Q$Refuse to display any sign. Live in truth. (Guardian)$Q$, $Q$Kein Schild zeigen. In der Wahrheit leben. (Wächter)$Q$, $Q$guardian$Q$, 5, $JB${"fracture": -3, "stress_heal": 15}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 10, "stress": 20}$JB$::jsonb, $Q$Living in truth. {agent} refuses. One person who refuses to perform exposes everyone else''s performance as a choice. The room changes. The signs are still there. But something has shifted.$Q$, $Q$In der Wahrheit leben. {agent} verweigert sich. Eine Person, die sich weigert aufzuführen, entlarvt die Aufführung aller anderen als Wahl. Der Raum verändert sich. Die Schilder sind noch da. Aber etwas hat sich verschoben.$Q$, $Q${agent} refuses. The room notices — but the silence that follows is ambiguous. Arendt''s distinction: liberation, not yet freedom. The signs remain. One person''s refusal is not yet contagious.$Q$, $Q${agent} verweigert sich. Der Raum bemerkt es — aber die Stille danach ist mehrdeutig. Arendts Unterscheidung: Befreiung, noch nicht Freiheit. Die Schilder bleiben. Die Verweigerung einer Person ist noch nicht ansteckend.$Q$, $Q$The refusal costs. Living in truth is the most expensive option in the Spiegelpalast.$Q$, $Q$Die Verweigerung kostet. In der Wahrheit leben ist die teuerste Option im Spiegelpalast.$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$greengrocer_subvert$Q$, $Q$ov_greengrocers_window$Q$, $Q$Display a sign with altered meaning (Saboteur)$Q$, $Q$Ein Schild mit veränderter Bedeutung zeigen (Saboteur)$Q$, $Q$saboteur$Q$, 0, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $Q$Détournement. Debord''s weapon: hijack the spectacle against itself. The sign says what it always said. The meaning has been reversed.$Q$, $Q$Détournement. Debords Waffe: das Spektakel gegen sich selbst wenden. Das Schild sagt, was es immer sagte. Die Bedeutung wurde umgekehrt.$Q$, $Q$The alteration holds — for now. Debord''s détournement, half-executed: the sign reads differently but {agent} cannot be sure who reads it which way. Ambiguity is a weapon that cuts both directions.$Q$, $Q$Die Veränderung hält — vorerst. Debords Détournement, halb ausgeführt: das Schild liest sich anders, aber {agent} kann nicht sicher sein, wer es wie liest. Mehrdeutigkeit ist eine Waffe, die in beide Richtungen schneidet.$Q$, $Q$The subversion is detected. The sign is confiscated. So is {agent}''s anonymity.$Q$, $Q$Die Subversion wird entdeckt. Das Schild wird konfisziert. Ebenso {agent}s Anonymität.$Q$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$portrait_remember$Q$, $Q$ov_erased_portrait$Q$, $Q$Reconstruct the erased faces (Spy)$Q$, $Q$Die gelöschten Gesichter rekonstruieren (Spion)$Q$, $Q$spy$Q$, 0, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $Q$The struggle against power is the struggle of memory against forgetting. {agent} remembers. The portraits do not reappear — but the party knows what was there.$Q$, $Q$Der Kampf gegen die Macht ist der Kampf der Erinnerung gegen das Vergessen. {agent} erinnert sich. Die Porträts erscheinen nicht wieder — aber die Gruppe weiß, was dort war.$Q$, $Q${agent} remembers some faces. Others dissolve — Kundera''s Clementis: the hat remains on Gottwald''s head, but whose hat was it? Memory reconstructs. Reconstruction edits.$Q$, $Q${agent} erinnert sich an einige Gesichter. Andere lösen sich auf — Kunderas Clementis: die Mütze bleibt auf Gottwalds Kopf, aber wessen Mütze war es? Erinnerung rekonstruiert. Rekonstruktion redigiert.$Q$, $Q$Memory fails. Not naturally — actively. Something in the Spiegelpalast assists forgetting.$Q$, $Q$Die Erinnerung versagt. Nicht natürlich — aktiv. Etwas im Spiegelpalast unterstützt das Vergessen.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$portrait_erase_more$Q$, $Q$ov_erased_portrait$Q$, $Q$Add current leaders to the erasure (Saboteur)$Q$, $Q$Aktuelle Anführer zur Löschung hinzufügen (Saboteur)$Q$, $Q$saboteur$Q$, 0, $JB${"fracture": 8}$JB$::jsonb, $JB${"fracture": 6}$JB$::jsonb, $JB${"fracture": 3, "stress": 5}$JB$::jsonb, $Q$Turnabout. {agent} scratches out the current leaders. The revolution that erased the old order is now being erased itself. The cycle continues.$Q$, $Q$Umkehr. {agent} kratzt die aktuellen Anführer aus. Die Revolution, die die alte Ordnung löschte, wird nun selbst gelöscht. Der Kreislauf geht weiter.$Q$, $Q${agent} scratches. Some faces are erased. Others resist — the paint is newer, the varnish thicker. Camus: every revolutionary ends as oppressor or heretic. The erasure is incomplete. So is the revolution.$Q$, $Q${agent} kratzt. Manche Gesichter werden gelöscht. Andere widerstehen — die Farbe ist neuer, der Lack dicker. Camus: jeder Revolutionär endet als Unterdrücker oder Ketzer. Die Löschung ist unvollständig. Die Revolution auch.$Q$, $Q$The scratching is noticed. Someone is always watching the watchers.$Q$, $Q$Das Kratzen wird bemerkt. Jemand beobachtet immer die Beobachter.$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$portrait_pass$Q$, $Q$ov_erased_portrait$Q$, $Q$Walk past. Do not engage with the erasure.$Q$, $Q$Vorbeigehen. Sich nicht auf die Löschung einlassen.$Q$, NULL, 0, $JB${"fracture": 3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party walks past. The gallery continues. There will be more portraits. There will be more erasures.$Q$, $Q$Die Gruppe geht vorbei. Die Galerie geht weiter. Es wird mehr Porträts geben. Es wird mehr Löschungen geben.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$theater_observe$Q$, $Q$ov_variety_theater$Q$, $Q$Watch the factions reveal themselves (Spy)$Q$, $Q$Beobachten, wie die Fraktionen sich offenbaren (Spion)$Q$, $Q$spy$Q$, -5, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 7, "stress": 5}$JB$::jsonb, $Q$Woland''s experiment, reproduced. {agent} watches. When given what they desire, every faction reveals what they truly are. The intelligence is invaluable.$Q$, $Q$Wolands Experiment, reproduziert. {agent} beobachtet. Wenn sie bekommen, was sie begehren, offenbart jede Fraktion, was sie wirklich ist. Die Aufklärung ist unbezahlbar.$Q$, $Q${agent} watches. Some factions reveal themselves. Others perform even while scrambling — Bulgakov''s observation: greed has its own theater. The picture is incomplete but telling.$Q$, $Q${agent} beobachtet. Manche Fraktionen offenbaren sich. Andere spielen auch beim Gerangel Theater — Bulgakows Beobachtung: Gier hat ihr eigenes Theater. Das Bild ist unvollständig, aber aufschlussreich.$Q$, $Q${agent} watches. But watching is also a position. The one who does not scramble is noticed.$Q$, $Q${agent} beobachtet. Aber Beobachten ist auch eine Position. Wer nicht mitrennt, wird bemerkt.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$theater_participate$Q$, $Q$ov_variety_theater$Q$, $Q$Join the scramble. Resources matter. (Infiltrator)$Q$, $Q$Mitmachen. Ressourcen zählen. (Infiltrator)$Q$, $Q$infiltrator$Q$, 0, $JB${"fracture": 5, "loot_tier": 1}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 8, "stress": 10}$JB$::jsonb, $Q$Erst kommt das Fressen, dann kommt die Moral. {agent} secures resources. The money may turn to paper. But the alliances formed during the scramble are real.$Q$, $Q$Erst kommt das Fressen, dann kommt die Moral. {agent} sichert Ressourcen. Das Geld mag zu Papier werden. Aber die Bündnisse, die beim Gerangel entstehen, sind echt.$Q$, $Q${agent} secures something — but the scramble is already sorting winners from losers. Brecht''s observation: the Fressen was real. Whether the Moral follows remains to be seen.$Q$, $Q${agent} sichert etwas — aber das Gerangel sortiert bereits Gewinner von Verlierern. Brechts Beobachtung: das Fressen war echt. Ob die Moral folgt, bleibt abzuwarten.$Q$, $Q$The scramble turns ugly. Material interest stripped of ideology. Brecht was right.$Q$, $Q$Das Gerangel wird hässlich. Materielles Interesse, von Ideologie befreit. Brecht hatte Recht.$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$theater_warn$Q$, $Q$ov_variety_theater$Q$, $Q$Warn the factions: this is a trap.$Q$, $Q$Die Fraktionen warnen: das ist eine Falle.$Q$, NULL, 0, $JB${"fracture": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The warning is issued. Some listen. Most do not. Manuscripts don''t burn. But money does.$Q$, $Q$Die Warnung wird ausgesprochen. Manche hören zu. Die meisten nicht. Manuskripte brennen nicht. Aber Geld schon.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 2) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$inquisitor_debate$Q$, $Q$ov_grand_inquisitor$Q$, $Q$Engage in philosophical debate (Propagandist)$Q$, $Q$Sich auf philosophische Debatte einlassen (Propagandist)$Q$, $Q$propagandist$Q$, 5, $JB${"fracture": -5, "stress_heal": 15}$JB$::jsonb, $JB${"fracture": 5}$JB$::jsonb, $JB${"fracture": 10, "stress": 20}$JB$::jsonb, $Q$Koestler''s two ethics, wielded against the Inquisitor. {agent} does not win the debate — {agent} makes the Inquisitor''s logic visible. The mechanism, once exposed, loses its hold.$Q$, $Q$Koestlers zwei Ethiken, gegen den Inquisitor gewandt. {agent} gewinnt die Debatte nicht — {agent} macht die Logik des Inquisitors sichtbar. Der Mechanismus, einmal entlarvt, verliert seinen Griff.$Q$, $Q$$Q$, $Q$$Q$, $Q$The Inquisitor''s logic is self-sealing. Given the premises, confession is the logical conclusion. {agent} follows the path and recoils.$Q$, $Q$Die Logik des Inquisitors ist selbstversiegelnd. Ausgehend von den Prämissen ist das Geständnis die logische Schlussfolgerung. {agent} folgt dem Pfad und schreckt zurück.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$inquisitor_fight$Q$, $Q$ov_grand_inquisitor$Q$, $Q$Reject the tribunal. Fight.$Q$, $Q$Das Tribunal ablehnen. Kämpfen.$Q$, NULL, 0, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$Words have failed. Or words were never the point. The Inquisitor rises. The informer reaches for a weapon.$Q$, $Q$Worte haben versagt. Oder Worte waren nie der Punkt. Der Inquisitor erhebt sich. Der Spitzel greift zur Waffe.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$safehouse_rest$Q$, $Q$ov_safe_house$Q$, $Q$Rest. Brief respite from the crisis.$Q$, $Q$Rasten. Kurze Atempause in der Krise.$Q$, NULL, 0, $JB${"stress_heal": 40, "fracture": -3}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party rests. Behind the wall, the factions continue without them. The rest is genuine. The safety is not.$Q$, $Q$Die Gruppe rastet. Hinter der Wand machen die Fraktionen ohne sie weiter. Die Rast ist echt. Die Sicherheit nicht.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$safehouse_eavesdrop$Q$, $Q$ov_safe_house$Q$, $Q$Listen through the wall (Spy)$Q$, $Q$Durch die Wand lauschen (Spion)$Q$, $Q$spy$Q$, -5, $JB${"stress_heal": 25, "fracture": 2}$JB$::jsonb, $JB${"stress_heal": 20}$JB$::jsonb, $JB${"stress_heal": 15, "stress": 5}$JB$::jsonb, $Q$Koestler''s tapping code. {agent} listens. The intelligence is useful. The knowledge that everyone is being discussed is less so.$Q$, $Q$Koestlers Klopfzeichen. {agent} lauscht. Die Aufklärung ist nützlich. Das Wissen, dass alle besprochen werden, weniger.$Q$, $Q$$Q$, $Q$$Q$, $Q$The wall is thinner than expected. In both directions.$Q$, $Q$Die Wand ist dünner als erwartet. In beiden Richtungen.$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$neutral_rest$Q$, $Q$ov_neutral_ground$Q$, $Q$Rest on neutral ground.$Q$, $Q$Auf neutralem Gelände rasten.$Q$, NULL, 0, $JB${"stress_heal": 50, "fracture": -5}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The boulder rests. The party rests. The silence is the first honest thing the Spiegelpalast has offered.$Q$, $Q$Der Felsbrocken ruht. Die Gruppe ruht. Die Stille ist das erste Ehrliche, das der Spiegelpalast angeboten hat.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$archive_study$Q$, $Q$ov_faction_archive$Q$, $Q$Study the dossiers carefully (Spy)$Q$, $Q$Die Dossiers sorgfältig studieren (Spion)$Q$, $Q$spy$Q$, -5, $JB${"fracture": 3, "loot_tier": 1}$JB$::jsonb, $JB${"fracture": 3, "loot_tier": 1}$JB$::jsonb, $JB${"fracture": 5, "stress": 5}$JB$::jsonb, $Q$Intelligence. Names, alliances, debts. {agent} takes what can be carried. The rest will be here for whoever comes next.$Q$, $Q$Aufklärung. Namen, Bündnisse, Schulden. {agent} nimmt, was getragen werden kann. Der Rest wird hier sein für den, der als Nächster kommt.$Q$, $Q$Names, alliances — but the debts are encoded. Kadare''s dream interpreters: the raw material is here. The interpretation requires context {agent} does not yet possess.$Q$, $Q$Namen, Bündnisse — aber die Schulden sind verschlüsselt. Kadares Traumdeuter: das Rohmaterial ist da. Die Interpretation erfordert Kontext, den {agent} noch nicht besitzt.$Q$, $Q$The dossiers are incomplete. Or they have been pre-edited for whoever found them.$Q$, $Q$Die Dossiers sind unvollständig. Oder sie wurden für den Finder vorbearbeitet.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$archive_take$Q$, $Q$ov_faction_archive$Q$, $Q$Take everything. Sort later.$Q$, $Q$Alles mitnehmen. Später sortieren.$Q$, NULL, 0, $JB${"fracture": 5, "loot_tier": 1}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$The party takes everything. Quantity over analysis. Somewhere in the stack is something important. Also somewhere in the stack: misinformation.$Q$, $Q$Die Gruppe nimmt alles mit. Quantität statt Analyse. Irgendwo im Stapel ist etwas Wichtiges. Ebenfalls irgendwo im Stapel: Desinformation.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$assets_salvage$Q$, $Q$ov_confiscated_assets$Q$, $Q$Salvage what is useful (Saboteur)$Q$, $Q$Retten, was nützlich ist (Saboteur)$Q$, $Q$saboteur$Q$, 0, $JB${"fracture": 3, "loot_tier": 1}$JB$::jsonb, $JB${"loot_tier": 1}$JB$::jsonb, $JB${"fracture": 5, "stress": 5}$JB$::jsonb, $Q${agent} finds something. The previous owner will not be needing it. The scratched-out name on the label tells its own story.$Q$, $Q${agent} findet etwas. Der vorherige Besitzer wird es nicht mehr brauchen. Der durchgestrichene Name auf dem Etikett erzählt seine eigene Geschichte.$Q$, $Q${agent} salvages. Some labels are legible, others deliberately smeared. Ngũgĩ''s observation: what the regime confiscates tells you what it fears. The catalogue is partial. The fear is not.$Q$, $Q${agent} birgt. Manche Etiketten sind lesbar, andere absichtlich verwischt. Ngũgĩs Beobachtung: was das Regime beschlagnahmt, verrät, wovor es sich fürchtet. Der Katalog ist unvollständig. Die Furcht nicht.$Q$, $Q$The assets are trapped — not physically, but politically. Taking them signals allegiance to the faction that confiscated them.$Q$, $Q$Die Güter sind eine Falle — nicht physisch, sondern politisch. Sie zu nehmen signalisiert Treue zur Fraktion, die sie beschlagnahmte.$Q$, 0) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_encounter_choices (id, encounter_id, label_en, label_de, check_aptitude, check_difficulty, success_effects, partial_effects, fail_effects, success_narrative_en, success_narrative_de, partial_narrative_en, partial_narrative_de, fail_narrative_en, fail_narrative_de, sort_order) VALUES ($Q$assets_leave$Q$, $Q$ov_confiscated_assets$Q$, $Q$Leave the dead their possessions.$Q$, $Q$Den Toten ihren Besitz lassen.$Q$, NULL, 0, $JB${"fracture": -2}$JB$::jsonb, $JB${}$JB$::jsonb, $JB${}$JB$::jsonb, $Q$Respect for the erased. The party takes nothing. In the Spiegelpalast, this is itself a political act.$Q$, $Q$Respekt vor den Gelöschten. Die Gruppe nimmt nichts. Im Spiegelpalast ist auch das ein politischer Akt.$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, $Q$$Q$, 1) ON CONFLICT (encounter_id, id) DO UPDATE SET encounter_id = EXCLUDED.encounter_id, label_en = EXCLUDED.label_en, label_de = EXCLUDED.label_de, check_aptitude = EXCLUDED.check_aptitude, check_difficulty = EXCLUDED.check_difficulty, success_effects = EXCLUDED.success_effects, partial_effects = EXCLUDED.partial_effects, fail_effects = EXCLUDED.fail_effects, success_narrative_en = EXCLUDED.success_narrative_en, success_narrative_de = EXCLUDED.success_narrative_de, partial_narrative_en = EXCLUDED.partial_narrative_en, partial_narrative_de = EXCLUDED.partial_narrative_de, fail_narrative_en = EXCLUDED.fail_narrative_en, fail_narrative_de = EXCLUDED.fail_narrative_de, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_faction_dossier$Q$, $Q$Faction Dossier$Q$, $Q$Fraktionsdossier$Q$, 1, $Q$stress_heal$Q$, $JB${"stress_heal": 50, "when": "after_dungeon"}$JB$::jsonb, $Q$Names, alliances, debts. Kadare's Palace of Dreams made portable. Knowledge is not power — knowledge is the absence of fear.$Q$, $Q$Namen, Bündnisse, Schulden. Kadares Palast der Träume, tragbar gemacht. Wissen ist nicht Macht — Wissen ist die Abwesenheit von Furcht.$Q$, 30, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_propaganda_leaflet$Q$, $Q$Propaganda Leaflet$Q$, $Q$Propagandaflugblatt$Q$, 1, $Q$aptitude_boost$Q$, $JB${"aptitude": "propagandist", "boost": 5, "duration_rooms": 5}$JB$::jsonb, $Q$Squealer's latest revision. The words are wrong but the technique is instructive.$Q$, $Q$Schwatzwutz' neueste Überarbeitung. Die Worte sind falsch, aber die Technik ist lehrreich.$Q$, 30, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_informers_list$Q$, $Q$Informer's List$Q$, $Q$Spitzelliste$Q$, 1, $Q$aptitude_boost$Q$, $JB${"aptitude": "spy", "boost": 5, "duration_rooms": 5}$JB$::jsonb, $Q$A list of names. Some are informers. Some are targets. The difference is a matter of perspective.$Q$, $Q$Eine Namensliste. Manche sind Spitzel. Manche sind Ziele. Der Unterschied ist eine Frage der Perspektive.$Q$, 25, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_safe_conduct$Q$, $Q$Safe Conduct Pass$Q$, $Q$Geleitbrief$Q$, 1, $Q$dungeon_buff$Q$, $JB${"stress_resist": 0.10, "duration_rooms": 4}$JB$::jsonb, $Q$Signed by a faction leader. Valid until the faction leader is replaced. Which could be any moment.$Q$, $Q$Unterschrieben von einem Fraktionsführer. Gültig, bis der Fraktionsführer ersetzt wird. Was jederzeit sein könnte.$Q$, 15, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_decoded_cipher$Q$, $Q$Decoded Cipher$Q$, $Q$Entschlüsselte Chiffre$Q$, 2, $Q$stress_heal$Q$, $JB${"stress_heal": 100, "when": "after_dungeon"}$JB$::jsonb, $Q$Faction communications, decoded. The content is less important than the fact of decoding. Manuscripts don't burn. But codes can be broken.$Q$, $Q$Fraktionskommunikation, entschlüsselt. Der Inhalt ist weniger wichtig als die Tatsache der Entschlüsselung. Manuskripte brennen nicht. Aber Codes können geknackt werden.$Q$, 25, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_seal_of_office$Q$, $Q$Seal of Office$Q$, $Q$Amtssiegel$Q$, 2, $Q$aptitude_boost$Q$, $JB${"aptitude": "propagandist", "boost": 10, "duration_rooms": 8}$JB$::jsonb, $Q$An official seal. The office no longer exists. The seal still carries weight — authority persists after the authority is gone.$Q$, $Q$Ein Amtssiegel. Das Amt existiert nicht mehr. Das Siegel hat noch Gewicht — Autorität besteht fort, nachdem die Autorität vergangen ist.$Q$, 25, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_double_agents_testimony$Q$, $Q$Double Agent's Testimony$Q$, $Q$Aussage des Doppelagenten$Q$, 2, $Q$dungeon_buff$Q$, $JB${"stress_resist": 0.15, "duration_rooms": 6}$JB$::jsonb, $Q$Ngũgĩ's informer-hero: the traitor whose confession is the most heroic act. This testimony protects because it reveals — and revelation is armor.$Q$, $Q$Ngũgĩs Spitzel-Held: der Verräter, dessen Geständnis die heldenhafteste Tat ist. Diese Aussage schützt, weil sie enthüllt — und Enthüllung ist Rüstung.$Q$, 25, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_erased_photograph$Q$, $Q$Erased Photograph$Q$, $Q$Gelöschtes Foto$Q$, 2, $Q$memory$Q$, $JB${"memory_text_en": "A photograph with a scratched-out face. The hat remains.", "memory_text_de": "Ein Foto mit ausgekratztem Gesicht. Die Mütze bleibt."}$JB$::jsonb, $Q$Kundera's Clementis photograph. The body erased, the fur hat remaining on Gottwald's head. Evidence that something was, before it was unmade.$Q$, $Q$Kunderas Clementis-Foto. Der Körper gelöscht, die Pelzmütze noch auf Gottwalds Kopf. Beweis, dass etwas war, bevor es ungemacht wurde.$Q$, 25, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_authority_fragment$Q$, $Q$Authority Fragment$Q$, $Q$Autoritätsfragment$Q$, 3, $Q$simulation_modifier$Q$, $JB${"security_boost": true, "duration_ticks": 10, "boost_amount": 1, "description_en": "A fragment of legitimate authority, salvaged from the Spiegelpalast. Upgrades one zone's security level by 1 tier for 10 heartbeat ticks.", "description_de": "Ein Fragment legitimer Autorität, aus dem Spiegelpalast geborgen. Erhöht die Sicherheitsstufe einer Zone um 1 Stufe für 10 Herzschlag-Ticks."}$JB$::jsonb, $Q$Spec loot: upgrades one zone's security_level by 1 tier for 10 heartbeat ticks. Authority, portable.$Q$, $Q$Spezifikationsbeute: erhöht die Sicherheitsstufe einer Zone um 1 Stufe für 10 Herzschlag-Ticks. Autorität, tragbar.$Q$, 30, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_colossus_splinter$Q$, $Q$Colossus Splinter$Q$, $Q$Koloss-Splitter$Q$, 3, $Q$simulation_modifier$Q$, $JB${"morale_boost": true, "duration_ticks": 10, "boost_amount": 0.15, "description_en": "La Boétie's Colossus: the tyrant whose pedestal was pulled away. A splinter of the fallen. All agents gain +15% morale for 10 heartbeat ticks.", "description_de": "La Boéties Koloss: der Tyrann, dessen Sockel weggezogen wurde. Ein Splitter des Gefallenen. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks."}$JB$::jsonb, $Q$A splinter from the Colossus that fell of its own weight. La Boétie's proof: tyranny requires consent. All agents gain +15% morale for 10 heartbeat ticks.$Q$, $Q$Ein Splitter des Kolosses, der unter seinem eigenen Gewicht fiel. La Boéties Beweis: Tyrannei braucht Zustimmung. Alle Agenten erhalten +15% Moral für 10 Herzschlag-Ticks.$Q$, 25, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_loot_items (id, name_en, name_de, tier, effect_type, effect_params, description_en, description_de, drop_weight, archetype) VALUES ($Q$overthrow_mirror_shard$Q$, $Q$Mirror Shard of the Spiegelpalast$Q$, $Q$Spiegelscherbe des Spiegelpalasts$Q$, 3, $Q$personality_modifier$Q$, $JB${"trait": "openness", "delta": 5, "description_en": "The mirror shows what the viewer wants, not what the viewer is. Openness +5.", "description_de": "Der Spiegel zeigt, was der Betrachter will, nicht was er ist. Offenheit +5."}$JB$::jsonb, $Q$A shard of the Spiegelpalast's central mirror. It still reflects — but what it reflects is no longer the room.$Q$, $Q$Eine Scherbe des zentralen Spiegels im Spiegelpalast. Sie reflektiert noch — aber was sie reflektiert, ist nicht mehr der Raum.$Q$, 20, $Q$The Overthrow$Q$) ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, tier = EXCLUDED.tier, effect_type = EXCLUDED.effect_type, effect_params = EXCLUDED.effect_params, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, drop_weight = EXCLUDED.drop_weight, archetype = EXCLUDED.archetype;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Overthrow$Q$, $Q$The threshold is a mirror. Not glass — political. Every reflection shows a different allegiance. Der Spiegelpalast does not ask who you are. It asks who you are for.$Q$, $Q$Die Schwelle ist ein Spiegel. Nicht Glas — politisch. Jede Spiegelung zeigt eine andere Treue. Der Spiegelpalast fragt nicht, wer ihr seid. Er fragt, für wen ihr seid.$Q$, 0) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Overthrow$Q$, $Q$The air smells of ink and ambition. Decrees are being written somewhere deeper. The decrees will contradict each other. Both will be enforced.$Q$, $Q$Die Luft riecht nach Tinte und Ehrgeiz. Irgendwo tiefer werden Dekrete geschrieben. Die Dekrete werden sich widersprechen. Beide werden durchgesetzt.$Q$, 1) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Overthrow$Q$, $Q$Factions. The word is not adequate. These are ecosystems of belief, each convinced of its own necessity. Machiavelli's fox and lion, multiplied.$Q$, $Q$Fraktionen. Das Wort ist nicht adäquat. Das sind Ökosysteme des Glaubens, jedes überzeugt von seiner eigenen Notwendigkeit. Machiavellis Fuchs und Löwe, multipliziert.$Q$, 2) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Overthrow$Q$, $Q$Power changes hands here. Not violently — procedurally. The forms are filled out. The signatures are forged. The forgeries are notarized.$Q$, $Q$Hier wechselt die Macht die Hände. Nicht gewaltsam — verfahrenstechnisch. Die Formulare werden ausgefüllt. Die Unterschriften werden gefälscht. Die Fälschungen werden beglaubigt.$Q$, 3) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_entrance_texts (archetype, text_en, text_de, sort_order) VALUES ($Q$The Overthrow$Q$, $Q$The descent begins. Not into darkness — into politics. The lighting is excellent. Everything is visible. Zamyatin's glass walls. Privacy is not forbidden. It is conceptually abolished.$Q$, $Q$Der Abstieg beginnt. Nicht in Dunkelheit — in Politik. Die Beleuchtung ist ausgezeichnet. Alles ist sichtbar. Zamjatins gläserne Wände. Privatsphäre ist nicht verboten. Sie ist begrifflich abgeschafft.$Q$, 4) ON CONFLICT (archetype, sort_order) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_faction_banner$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A banner. The insignia is familiar — from two rooms ago, where it meant something different.", "text_de": "Ein Banner. Das Abzeichen ist vertraut — aus zwei Räumen zuvor, wo es etwas anderes bedeutete."}, "echo": {"text_en": "The banner has been turned inside out. The same insignia, reversed. A faction's mirror image.", "text_de": "Das Banner wurde umgedreht. Dasselbe Abzeichen, gespiegelt. Das Spiegelbild einer Fraktion."}, "mutation": {"text_en": "The banner bears no insignia now. It bears a mirror. The mirror reflects whoever looks at it in faction colors.", "text_de": "Das Banner trägt jetzt kein Abzeichen. Es trägt einen Spiegel. Der Spiegel reflektiert jeden, der hinsieht, in Fraktionsfarben."}, "climax": {"text_en": "The banner is blank. All factions have claimed it. All factions have abandoned it. It flies for no one.", "text_de": "Das Banner ist leer. Alle Fraktionen haben es beansprucht. Alle Fraktionen haben es aufgegeben. Es weht für niemanden."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_decree_stone$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A stone tablet with a decree. The ink is fresh. The decree is reasonable.", "text_de": "Eine Steintafel mit einem Dekret. Die Tinte ist frisch. Das Dekret ist vernünftig."}, "echo": {"text_en": "The decree has been amended. The amendment contradicts the original. Both remain binding.", "text_de": "Das Dekret wurde ergänzt. Die Ergänzung widerspricht dem Original. Beide bleiben bindend."}, "mutation": {"text_en": "The stone now bears three decrees. They form a triangle of mutual contradiction. Shigalyov's paradox, petrified.", "text_de": "Der Stein trägt jetzt drei Dekrete. Sie bilden ein Dreieck gegenseitigen Widerspruchs. Schigaljows Paradox, versteinert."}, "climax": {"text_en": "The decree stone is blank. Not erased — never inscribed. The authority to decree has been decreed nonexistent.", "text_de": "Der Dekretstein ist leer. Nicht gelöscht — nie beschrieben. Die Autorität zu dekretieren wurde für inexistent dekretiert."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_informers_clipboard$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A clipboard with names. Some checked off. The party's names are listed but not yet checked.", "text_de": "Ein Klemmbrett mit Namen. Einige abgehakt. Die Namen der Gruppe sind aufgelistet, aber noch nicht abgehakt."}, "echo": {"text_en": "The clipboard has grown. More names. The handwriting changes — multiple informers, same list.", "text_de": "Das Klemmbrett ist gewachsen. Mehr Namen. Die Handschrift wechselt — mehrere Spitzel, dieselbe Liste."}, "mutation": {"text_en": "The informer's name is on the list now. The informer is being informed on. The system is recursive.", "text_de": "Der Name des Spitzels steht jetzt auf der Liste. Der Spitzel wird bespitzelt. Das System ist rekursiv."}, "climax": {"text_en": "Every name on the list is checked off. The list continues. There are no names left to check. The checking continues.", "text_de": "Jeder Name auf der Liste ist abgehakt. Die Liste geht weiter. Es gibt keine Namen mehr zum Abhaken. Das Abhaken geht weiter."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_trial_chair$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "An empty chair in the center of a room. The room is arranged for a tribunal. The chair is for the accused.", "text_de": "Ein leerer Stuhl in der Mitte eines Raums. Der Raum ist für ein Tribunal eingerichtet. Der Stuhl ist für den Angeklagten."}, "echo": {"text_en": "The chair has been occupied. Recently. The warmth is still there. The verdict has already been passed.", "text_de": "Der Stuhl war besetzt. Kürzlich. Die Wärme ist noch da. Das Urteil wurde bereits gefällt."}, "mutation": {"text_en": "The chair faces a mirror now. The accused watches their own trial. Kiš's archival voice narrates in footnotes.", "text_de": "Der Stuhl steht jetzt vor einem Spiegel. Der Angeklagte beobachtet seinen eigenen Prozess. Kišs Archivstimme erzählt in Fußnoten."}, "climax": {"text_en": "The chair is for the judge now. The accused is gone. The judge sits and realizes: the next trial is their own.", "text_de": "Der Stuhl ist jetzt für den Richter. Der Angeklagte ist weg. Der Richter sitzt und erkennt: der nächste Prozess ist der eigene."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_mirror_corridor$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "Mirrors on both walls. The reflections are accurate. Suspiciously accurate.", "text_de": "Spiegel an beiden Wänden. Die Spiegelungen sind exakt. Verdächtig exakt."}, "echo": {"text_en": "The reflections are slightly ahead of the party. They know where the party is going before the party does.", "text_de": "Die Spiegelungen sind der Gruppe leicht voraus. Sie wissen, wohin die Gruppe geht, bevor die Gruppe es weiß."}, "mutation": {"text_en": "The reflections wear different faction insignia than the party. The mirror shows allegiance, not appearance.", "text_de": "Die Spiegelungen tragen andere Fraktionsabzeichen als die Gruppe. Der Spiegel zeigt Treue, nicht Aussehen."}, "climax": {"text_en": "The mirrors face each other. Infinite recursion. Infinite factions. The Pretender is in every reflection.", "text_de": "Die Spiegel stehen sich gegenüber. Unendliche Rekursion. Unendliche Fraktionen. Der Prätendent ist in jeder Spiegelung."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_propaganda_poster$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A poster. The message is clear, the design effective. Orwell's Squealer would approve.", "text_de": "Ein Plakat. Die Botschaft ist klar, das Design wirkungsvoll. Orwells Schwatzwutz würde zustimmen."}, "echo": {"text_en": "The poster has been pasted over with a new one. The new poster says the opposite. The adhesive is the same.", "text_de": "Das Plakat wurde mit einem neuen überklebt. Das neue Plakat sagt das Gegenteil. Der Klebstoff ist derselbe."}, "mutation": {"text_en": "Both posters are visible now, layered. The contradiction is the message. Doublethink, illustrated.", "text_de": "Beide Plakate sind jetzt sichtbar, geschichtet. Der Widerspruch ist die Botschaft. Doppeldenk, illustriert."}, "climax": {"text_en": "The poster is blank. Not torn down — never printed. The propaganda has moved from paper into the air itself.", "text_de": "Das Plakat ist leer. Nicht abgerissen — nie gedruckt. Die Propaganda ist vom Papier in die Luft selbst übergegangen."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_scales_of_justice$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "Balanced scales. Both pans empty. The balance is perfect because nothing is being weighed.", "text_de": "Ausbalancierte Waage. Beide Schalen leer. Die Balance ist perfekt, weil nichts gewogen wird."}, "echo": {"text_en": "One pan holds a faction seal. The other holds a different faction seal. They weigh exactly the same.", "text_de": "Eine Schale hält ein Fraktionssiegel. Die andere ein anderes Fraktionssiegel. Sie wiegen genau gleich."}, "mutation": {"text_en": "A thumb on the scale. Whose thumb? The mirror behind the scales does not show a hand.", "text_de": "Ein Daumen auf der Waage. Wessen Daumen? Der Spiegel hinter der Waage zeigt keine Hand."}, "climax": {"text_en": "The scales tip. Both pans hit the ground simultaneously. Justice is not blind — justice has been dismissed.", "text_de": "Die Waage kippt. Beide Schalen treffen gleichzeitig den Boden. Gerechtigkeit ist nicht blind — Gerechtigkeit wurde entlassen."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_colossus_pedestal$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "An empty pedestal. Something large stood here. The shadow remains on the floor.", "text_de": "Ein leerer Sockel. Etwas Großes stand hier. Der Schatten bleibt auf dem Boden."}, "echo": {"text_en": "The pedestal bears an inscription: 'Resolve to serve no more, and you are at once freed.' La Boétie.", "text_de": "Der Sockel trägt eine Inschrift: 'Beschließe, nicht mehr zu dienen, und du bist sogleich befreit.' La Boétie."}, "mutation": {"text_en": "Cracks in the pedestal. The Colossus did not fall — it was pulled. From below. By those who built it.", "text_de": "Risse im Sockel. Der Koloss ist nicht gefallen — er wurde gezogen. Von unten. Von denen, die ihn gebaut haben."}, "climax": {"text_en": "The pedestal is being rebuilt. For a new Colossus. The builders are the same. The blueprints are the same.", "text_de": "Der Sockel wird wieder aufgebaut. Für einen neuen Koloss. Die Baumeister sind dieselben. Die Baupläne sind dieselben."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 0, $Q$The authority holds.$Q$, $Q$Die Autorität hält.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 1, $Q$The authority whispers.$Q$, $Q$Die Autorität flüstert.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 2, $Q$The authority fractures.$Q$, $Q$Die Autorität bricht.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 3, $Q$The authority is a mirror.$Q$, $Q$Die Autorität ist ein Spiegel.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
